import{_ as t,o as a,c as e,a4 as s}from"./chunks/framework.Bz0lZ1uX.js";const _=JSON.parse('{"title":"马丁·路德·金 - 非暴力抗争的民权领袖","description":"","frontmatter":{},"headers":[],"relativePath":"materials/人物素材/社会活动家/马丁·路德·金.md","filePath":"materials/人物素材/社会活动家/马丁·路德·金.md","lastUpdated":null}'),l={name:"materials/人物素材/社会活动家/马丁·路德·金.md"},r=s('<h1 id="马丁·路德·金-非暴力抗争的民权领袖" tabindex="-1">马丁·路德·金 - 非暴力抗争的民权领袖 <a class="header-anchor" href="#马丁·路德·金-非暴力抗争的民权领袖" aria-label="Permalink to &quot;马丁·路德·金 - 非暴力抗争的民权领袖&quot;">​</a></h1><p><strong>标签</strong>: #社会活动家 #平等 #正义 #信念 #梦想 #勇气 #非暴力抗争 #诺贝尔奖</p><hr><h2 id="核心事迹简介" tabindex="-1">核心事迹简介 <a class="header-anchor" href="#核心事迹简介" aria-label="Permalink to &quot;核心事迹简介&quot;">​</a></h2><p>马丁·路德·金，美国民权运动领袖，诺贝尔和平奖得主。1963年，他在林肯纪念堂台阶上发表了震烁古今的《我有一个梦想》演说，以非暴力抗争的方式呼唤种族平等与正义。他的呐喊唤醒了无数沉睡的灵魂，推动了《民权法案》的诞生，虽最终为理想献身，却用生命铸就了人类追求自由平等的丰碑。</p><hr><h2 id="考场议论文论证片段" tabindex="-1">考场议论文论证片段 <a class="header-anchor" href="#考场议论文论证片段" aria-label="Permalink to &quot;考场议论文论证片段&quot;">​</a></h2><h3 id="片段1-个人品质角度" tabindex="-1">片段1（个人品质角度） <a class="header-anchor" href="#片段1-个人品质角度" aria-label="Permalink to &quot;片段1（个人品质角度）&quot;">​</a></h3><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>坚定的信念，是冲破黑暗牢笼的唯一利刃。在那个种族隔离森严的年代，马丁·路德·金没有选择沉默，更没有选择以暴制暴，而是高举&quot;非暴力不合作&quot;的旗帜，直面高压水枪与警棒的威胁。他在林肯纪念堂前那句&quot;我有一个梦想&quot;，并非一时激昂的口号，而是无数次抗争与坐牢后依然挺立的脊梁。他用生命诠释了：真正的勇者，不是没有恐惧，而是在恐惧中依然选择为了正义负重前行。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="片段2-时代价值角度" tabindex="-1">片段2（时代价值角度） <a class="header-anchor" href="#片段2-时代价值角度" aria-label="Permalink to &quot;片段2（时代价值角度）&quot;">​</a></h3><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>一个人的梦想，可以点燃整个时代的希望之火。马丁·路德·金的演讲，不仅撕裂了美国社会种族歧视的坚冰，更推动了《民权法案》的落地，让&quot;人人生而平等&quot;的宣言不再是一纸空文。他的抗争超越了肤色与国界，成为人类文明进程中追求尊严与自由的永恒坐标。历史证明，当一个人的声音汇聚了万千民众的渴望，便能化作推动社会进步的滔滔巨浪，让正义的光芒普照大地的每一个角落。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="适用高考作文主题" tabindex="-1">适用高考作文主题 <a class="header-anchor" href="#适用高考作文主题" aria-label="Permalink to &quot;适用高考作文主题&quot;">​</a></h2><p>平等 · 正义 · 信念 · 梦想 · 勇气 · 非暴力抗争</p><hr><h2 id="高中作文写作建议" tabindex="-1">高中作文写作建议 <a class="header-anchor" href="#高中作文写作建议" aria-label="Permalink to &quot;高中作文写作建议&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">具体建议</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>段落位置</strong></td><td style="text-align:left;">适合用于开头引出话题，或作为核心论据论证&quot;信念的力量&quot;或&quot;社会变革&quot;。</td></tr><tr><td style="text-align:left;"><strong>过渡句式</strong></td><td style="text-align:left;">可运用&quot;正如马丁·路德·金所言……&quot;或&quot;从……到……，无不昭示着……&quot;自然引入。</td></tr><tr><td style="text-align:left;"><strong>扣题方法</strong></td><td style="text-align:left;">在引用《我有一个梦想》后，必须紧跟一句分析，点明&quot;梦想不仅是愿景，更是行动的指南&quot;。</td></tr><tr><td style="text-align:left;"><strong>立意升格</strong></td><td style="text-align:left;">可将种族平等的诉求升格为对&quot;人类命运共同体&quot;的思考，探讨如何在多元世界中寻求共识与和谐。</td></tr></tbody></table>',17),n=[r];function o(i,d,h,u,c,p){return a(),e("div",null,n)}const g=t(l,[["render",o]]);export{_ as __pageData,g as default};
